1	// `Prot::RO_CODE` / `Prot::RO_DATA` and `AddrSpace::unmap_page` are part of
2	// the API surface that slice 3.1b's per-proc TTBR0 wiring and slice 3.3's
3	// `SYS_VMCTL` subcalls will consume; 3.1a's smoke test only exercises
4	// `Prot::RW_DATA` + `map_page`. Surfacing them now keeps the API stable
5	// across the two slices.
6	#![allow(dead_code)]
7	
8	//! Per-process aarch64 address space.
9	//!
10	//! Slice 3.1a introduces this API but no proc consumes it yet — the kmain
11	//! smoke test exercises it standalone, and slice 3.1b will swap `userland.rs`
12	//! over so each EL0 stub gets its own [`AddrSpace`] instead of the shared
13	//! static L0/L1/L2/L3 arrays.
14	//!
15	//! The walk follows the same 4 KiB-granule, 4-level, 48-bit-VA layout that
16	//! [`super::mmu`] already documents and verifies on Limine handoff. Intermediate
17	//! tables (L1, L2, L3) are allocated on demand from the frame allocator —
18	//! [`AddrSpace::new`] only allocates the L0 root; each `map_page` walk
19	//! allocates whatever sub-tables are missing.
20	//!
21	//! All page-table writes go through HHDM — we never touch a table via its
22	//! own VA, because at slice-3.1a time the address space isn't activated.
23	//! Slice 3.1b's context switch will install [`AddrSpace::ttbr0_pa`] into
24	//! TTBR0_EL1; until then, AddrSpaces are passive data structures.
25	
26	use crate::arch::aarch64::mmu::{
27	    ATTR_IDX_NORMAL, PAGE_SHIFT, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
28	    PTE_SH_INNER, PTE_TABLE, PTE_UXN, PTE_VALID, PTES_PER_LEVEL, pte_attr_idx,
29	};
30	use crate::mm::{FRAME_SIZE, Frame, alloc_frame, free_frame, phys_to_hhdm};
31	
32	/// User-page permission. Maps onto the aarch64 stage-1 descriptor's AP +
33	/// PXN + UXN bits; kernel callers describe intent here and `prot_attrs()`
34	/// converts to the bit pattern.
35	#[derive(Copy, Clone, Debug)]
36	pub struct Prot {
37	    /// EL0 may write.
38	    pub writable: bool,
39	    /// EL0 may fetch from this page (code).
40	    pub executable: bool,
41	}
42	
43	impl Prot {
44	    pub const RO_CODE: Self = Self { writable: false, executable: true };
45	    pub const RW_DATA: Self = Self { writable: true, executable: false };
46	    pub const RO_DATA: Self = Self { writable: false, executable: false };
47	}
48	
49	fn prot_attrs(prot: Prot) -> u64 {
50	    let ap = if prot.writable { PTE_AP_RW_EL0 } else { PTE_AP_RO_EL0 };
51	    let uxn = if prot.executable { 0 } else { PTE_UXN };
52	    PTE_AF | PTE_SH_INNER | ap | PTE_PXN | uxn | pte_attr_idx(ATTR_IDX_NORMAL)
53	}
54	
55	/// Errors from [`AddrSpace`] operations.
56	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
57	pub enum MapError {
58	    /// Frame allocator returned `None`; no physical memory left for an
59	    /// intermediate page table or for the L0 root.
60	    OutOfMemory,
61	    /// `va` is not 4 KiB-aligned.
62	    Misaligned,
63	    /// `va` is outside the 48-bit user-VA window.
64	    OutOfRange,
65	    /// A leaf PTE is already present at `va` and the caller asked for a
66	    /// fresh mapping. Use [`AddrSpace::unmap_page`] to clear first.
67	    AlreadyMapped,
68	}
69	
70	/// One per-process page-table tree, rooted at the L0 frame whose PA goes
71	/// into TTBR0_EL1 on context switch.
72	pub struct AddrSpace {
73	    /// PA of the L0 page-table root. Always frame-aligned.
74	    pub ttbr0_pa: u64,
75	}
76	
77	impl AddrSpace {
78	    /// Build a fresh, empty address space. Allocates one frame for the L0
79	    /// root; intermediate L1/L2/L3 tables come later, on first `map_page`.
80	    pub fn new() -> Result<Self, MapError> {
81	        let l0 = alloc_frame().ok_or(MapError::OutOfMemory)?;
82	        // `alloc_frame` zeroes the frame, so the L0 starts all-invalid.
83	        Ok(Self { ttbr0_pa: l0.addr() })
84	    }
85	
86	    /// Install a single 4 KiB mapping `va → pa` with the given permissions.
87	    ///
88	    /// Intermediate L1/L2/L3 tables are allocated from the frame allocator
89	    /// as needed. Returns `Err(AlreadyMapped)` if `va` already has a leaf
90	    /// PTE (callers must `unmap_page` first to replace).
91	    pub fn map_page(&mut self, va: u64, pa: u64, prot: Prot) -> Result<(), MapError> {
92	        check_va(va)?;
93	        if pa & (FRAME_SIZE as u64 - 1) != 0 {
94	            return Err(MapError::Misaligned);
95	        }
96	
97	        let l0 = self.ttbr0_pa;
98	        let l1 = ensure_next_table(l0, pte_index(va, 0))?;
99	        let l2 = ensure_next_table(l1, pte_index(va, 1))?;
100	        let l3 = ensure_next_table(l2, pte_index(va, 2))?;
101	        let l3_table = table_mut(l3);
102	        let idx = pte_index(va, 3);
103	        if l3_table[idx] & PTE_VALID != 0 {
104	            return Err(MapError::AlreadyMapped);
105	        }
106	        l3_table[idx] = make_page_desc(pa, prot_attrs(prot));
107	        Ok(())
108	    }
109	
110	    /// Clear the leaf PTE at `va`. Returns `Some(pa)` if a mapping was
111	    /// present, `None` otherwise. The freed PA is returned to the caller —
112	    /// it's the caller's job to `free_frame` if appropriate (the page
113	    /// might be a CoW share, a device PA, or stale; the address space
114	    /// itself doesn't know).
115	    ///
116	    /// Does not free intermediate L1/L2/L3 tables even if they become
117	    /// empty — that's left to [`Self::destroy`]. Avoiding incremental
118	    /// pruning keeps `unmap_page` O(walk) and matches what real MINIX 3
119	    /// does (lazy pruning at exec/exit time).
120	    pub fn unmap_page(&mut self, va: u64) -> Option<u64> {
121	        check_va(va).ok()?;
122	        let l0 = self.ttbr0_pa;
123	        let l1 = next_table(l0, pte_index(va, 0))?;
124	        let l2 = next_table(l1, pte_index(va, 1))?;
125	        let l3 = next_table(l2, pte_index(va, 2))?;
126	        let l3_table = table_mut(l3);
127	        let idx = pte_index(va, 3);
128	        let pte = l3_table[idx];
129	        if pte & PTE_VALID == 0 {
130	            return None;
131	        }
132	        l3_table[idx] = 0;
133	        Some(pte & PA_MASK)
134	    }
135	
136	    /// Walk the page table to find the PA backing `va`, or `None` if `va`
137	    /// is unmapped.
138	    pub fn walk_pt(&self, va: u64) -> Option<u64> {
139	        check_va(va).ok()?;
140	        let l0 = self.ttbr0_pa;
141	        let l1 = next_table(l0, pte_index(va, 0))?;
142	        let l2 = next_table(l1, pte_index(va, 1))?;
143	        let l3 = next_table(l2, pte_index(va, 2))?;
144	        let pte = table_ref(l3)[pte_index(va, 3)];
145	        if pte & PTE_VALID == 0 {
146	            None
147	        } else {
148	            Some(pte & PA_MASK)
149	        }
150	    }
151	
152	    /// Free every intermediate L1/L2/L3 table and the L0 root.
153	    ///
154	    /// Leaf-page frames (the PAs that `map_page` installed) are *not*
155	    /// freed — the address space owns the page-table tree, not the pages
156	    /// it points at. The caller is responsible for tracking and freeing
157	    /// leaf frames before calling this; otherwise they leak. Phase 3.5's
158	    /// VM region tracker is what eventually owns leaf-frame lifetimes.
159	    pub fn destroy(self) {
160	        // Walk the L0 root, recursing into table descriptors. Page
161	        // descriptors (PTE_VALID & PTE_TABLE both set at L3) are leaves
162	        // and left alone; intermediate tables (PTE_VALID & PTE_TABLE at
163	        // L0/L1/L2) get recursed-into then freed.
164	        free_subtree(self.ttbr0_pa, 0);
165	        free_frame(Frame::from_addr(self.ttbr0_pa));
166	    }
167	}
168	
169	// ----- helpers --------------------------------------------------------------
170	
171	/// Mask selecting the PA bits of a descriptor (47:12).
172	const PA_MASK: u64 = 0x0000_FFFF_FFFF_F000;
173	
174	/// One 48-bit user VA past the last legal address: `1 << 48`.
175	const USER_VA_TOP: u64 = 1 << 48;
176	
177	fn check_va(va: u64) -> Result<(), MapError> {
178	    if va & (FRAME_SIZE as u64 - 1) != 0 {
179	        return Err(MapError::Misaligned);
180	    }
181	    if va >= USER_VA_TOP {
182	        return Err(MapError::OutOfRange);
183	    }
184	    Ok(())
185	}
186	
187	fn pte_index(va: u64, level: u32) -> usize {
188	    let shift = PAGE_SHIFT + 9 * (3 - level);
189	    ((va >> shift) & 0x1FF) as usize
190	}
191	
192	const fn make_table_desc(next_table_pa: u64) -> u64 {
193	    (next_table_pa & PA_MASK) | PTE_VALID | PTE_TABLE
194	}
195	
196	const fn make_page_desc(pa: u64, attrs: u64) -> u64 {
197	    // At L3, both PTE_VALID and PTE_TABLE bits must be set to distinguish a
198	    // page descriptor from an invalid entry. `mmu::make_page_desc` documents
199	    // this; we mirror the same encoding.
200	    (pa & PA_MASK) | PTE_VALID | PTE_TABLE | attrs
201	}
202	
203	/// Borrow the 512-entry table at `table_pa` via HHDM for read.
204	fn table_ref(table_pa: u64) -> &'static [u64; PTES_PER_LEVEL] {
