175	/// translation regime. The kernel never installs a custom TTBR1.
176	///
177	/// SAFETY: must be called with DAIF masked at EL1, single-threaded boot.
178	/// `ttbr0_pa` must point at a valid L0 page table the caller owns.
179	pub unsafe fn switch_ttbr0_with_asid(ttbr0_pa: u64, asid: u8) {
180	    debug_assert!(asid != 0, "switch_ttbr0_with_asid: ASID 0 is reserved");
181	    debug_assert!(
182	        ttbr0_pa & (PAGE_SIZE as u64 - 1) == 0,
183	        "switch_ttbr0_with_asid: ttbr0_pa not page-aligned",
184	    );
185	    let tagged = ttbr0_pa | ((asid as u64) << 48);
186	    // `tlbi aside1, Xt` consumes the ASID from bits [63:48] of Xt; the
187	    // remaining bits are RES0 / SBZ. We pass the same `asid << 48` we
188	    // used for TTBR0 — keeps the encoding self-documenting.
189	    //
190	    // SAFETY: TTBR0_EL1 and TLBI ASIDE1 are EL1 ops with no normal-memory
191	    // access. The ISB after MSR ensures the new TTBR0 is observed before
192	    // the TLBI; the DSB ISH after the TLBI completes the invalidate; the
193	    // trailing ISB context-synchronizes before the subsequent eret.
194	    unsafe {
195	        asm!(
196	            "msr ttbr0_el1, {ttbr}",
197	            "isb",
198	            "tlbi aside1, {asid_x}",
199	            "dsb ish",
200	            "isb",
201	            ttbr = in(reg) tagged,
202	            asid_x = in(reg) (asid as u64) << 48,
203	            options(nomem, nostack, preserves_flags),
204	        );
205	    }
206	}
207	
208	/// Make instruction memory coherent with a recent data write at `va..va+len`.
209	///
210	/// AArch64 caches are PIPT for data but VIPT-flavored for instructions; after
211	/// writing into a code page we must clean the data side to PoU, then
212	/// invalidate the i-cache. Sequence is straight out of the ARM ARM §B2.4
213	/// example.
214	///
215	/// SAFETY: `va..va+len` must be a valid mapped range readable at EL1.
216	pub unsafe fn flush_icache_range(va: u64, len: usize) {
217	    // CTR_EL0.DminLine (bits 19:16) = log2 of the minimum D-cache line
218	    // size in words; multiply by the 4 B word size to get bytes. QEMU virt
219	    // reports 64 here; Apple Silicon reports 128.
220	    let ctr: u64;
221	    // SAFETY: CTR_EL0 is readable at EL1; no side effects.
222	    unsafe {
223	        asm!("mrs {0}, ctr_el0", out(reg) ctr, options(nomem, nostack, preserves_flags));
224	    }
225	    let line_bytes = 4_u64 << ((ctr >> 16) & 0xF);
226	
227	    let mut p = va & !(line_bytes - 1);
228	    let end = va + len as u64;
229	    while p < end {
230	        // SAFETY: `dc cvau` / `ic ivau` are EL0-permissive cache ops on a
231	        // VA already known to be mapped; no memory access semantically.
232	        unsafe {
233	            asm!("dc cvau, {0}", in(reg) p, options(nostack, preserves_flags));
234	        }
235	        p += line_bytes;
236	    }
237	    // SAFETY: barrier + i-cache invalidation; no memory access.
238	    unsafe {
239	        asm!(
240	            "dsb ish",
241	            "ic iallu",
242	            "dsb ish",
243	            "isb",
244	            options(nomem, nostack, preserves_flags),
245	        );
246	    }
247	}

